import React, { useState } from 'react';

const fmt = (n) =>
  Intl.NumberFormat('en-IN', { style: 'currency', currency: 'INR', maximumFractionDigits: 0 }).format(n);

function getSlabRows(salary) {
  const rows = [];
  if (salary <= 250000) {
    rows.push({ label: '0 - 2.5L', amount: salary, rate: '0%', tax: 0 });
    return { rows, surcharge: 0 };
  }
  rows.push({ label: '0 - 2.5L', amount: 250000, rate: '0%', tax: 0 });
  if (salary > 250000) {
    const amt = Math.min(salary - 250000, 250000);
    rows.push({ label: '2.5L - 5L', amount: amt, rate: '10%', tax: Math.round(amt * 0.1) });
  }
  if (salary > 500000) {
    const amt = Math.min(salary - 500000, 500000);
    rows.push({ label: '5L - 10L', amount: amt, rate: '20%', tax: Math.round(amt * 0.2) });
  }
  if (salary > 1000000) {
    const amt = salary - 1000000;
    rows.push({ label: 'Above 10L', amount: amt, rate: '25%', tax: Math.round(amt * 0.25) });
  }
  let slabTax = rows.reduce((s, r) => s + r.tax, 0);
  const surcharge = slabTax > 50000 ? Math.round((slabTax - 50000) * 0.05) : 0;
  return { rows, surcharge };
}

function SlabBreakdown({ salary }) {
  const { rows, surcharge } = getSlabRows(salary);
  return (
    <div className="slab-breakdown">
      <table>
        <thead>
          <tr>
            <th>Slab</th>
            <th>Taxable amount</th>
            <th>Rate</th>
            <th>Tax</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i} className="slab-row">
              <td>{r.label}</td>
              <td>{fmt(r.amount)}</td>
              <td>{r.rate}</td>
              <td>{fmt(r.tax)}</td>
            </tr>
          ))}
          {surcharge > 0 && (
            <tr className="slab-row surcharge-row">
              <td colSpan="2">Surcharge (5% on tax above ₹50,000)</td>
              <td>5%</td>
              <td>{fmt(surcharge)}</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

function EmployeeRow({ emp }) {
  const [open, setOpen] = useState(false);
  const pctTax = emp.salary > 0 ? (emp.tax / emp.salary) * 100 : 0;
  const pctTake = emp.salary > 0 ? (emp.takeHome / emp.salary) * 100 : 0;
  const effRate = emp.salary > 0 ? ((emp.tax / emp.salary) * 100).toFixed(1) : '0';

  return (
    <>
      <tr className="employee-row" onClick={() => setOpen((o) => !o)}>
        <td>
          <span className="index-badge">#{emp.index}</span>
        </td>
        <td className="num">{fmt(emp.salary)}</td>
        <td className="num">
          {fmt(emp.tax)} <span className="rate-pill">{effRate}%</span>
        </td>
        <td className="num">{fmt(emp.takeHome)}</td>
        <td className="bar-cell">
          <div className="bar-wrap">
            <div className="bar bar-take" style={{ width: `${pctTake}%` }} />
            <div className="bar bar-tax" style={{ width: `${pctTax}%` }} />
          </div>
        </td>
        <td>
          <span className={`arrow ${open ? 'open' : ''}`}>▼</span>
        </td>
      </tr>
      {open && (
        <tr className="expand-row">
          <td colSpan="6">
            <SlabBreakdown salary={emp.salary} />
          </td>
        </tr>
      )}
    </>
  );
}

function App() {
  const [numEmployees, setNumEmployees] = useState('');
  const [totalSalary, setTotalSalary] = useState('');
  const [results, setResults] = useState(null);
  const [totalTax, setTotalTax] = useState(null);
  const [totalTakeHome, setTotalTakeHome] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const handleCalculate = async () => {
    setError(null);
    const n = parseInt(numEmployees, 10);
    const total = parseFloat(totalSalary);
    if (!n || n < 1 || !total || total < 0) {
      setError('Enter valid employee count and total salary');
      return;
    }
    setLoading(true);
    try {
      const res = await fetch('/api/calculate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ numEmployees: n, totalSalary: total })
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || 'Calculation failed');
      setResults(data.employees);
      setTotalTax(data.totalTax);
      setTotalTakeHome(data.totalTakeHome);
    } catch (err) {
      setError(err.message || 'Something went wrong');
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
    setResults(null);
    setTotalTax(null);
    setTotalTakeHome(null);
    setError(null);
  };

  const hasResults = results && results.length > 0;
  const payroll = hasResults ? results.reduce((s, e) => s + e.salary, 0) : 0;
  const effTaxPct = payroll > 0 && totalTax != null ? ((totalTax / payroll) * 100).toFixed(1) : '0';

  return (
    <div className="app">
      <header className="header">
        <div className="header-bar" />
        <div className="header-inner">
          <span className="logo-icon">◈</span>
          <h1>Employee Tax Minimization Calculator</h1>
        </div>
      </header>

      <main className="main">
        <section className="input-section">
          <div className="input-grid">
            <label>
              Number of Employees
              <input
                type="number"
                min="1"
                value={numEmployees}
                onChange={(e) => setNumEmployees(e.target.value)}
                disabled={loading}
              />
            </label>
            <label>
              Cumulative Yearly Pay (₹)
              <input
                type="number"
                min="0"
                step="1000"
                value={totalSalary}
                onChange={(e) => setTotalSalary(e.target.value)}
                disabled={loading}
              />
            </label>
          </div>
          {error && <div className="error-msg">{error}</div>}
          <div className="btn-row">
            <button type="button" className="btn btn-primary" onClick={handleCalculate} disabled={loading}>
              {loading ? <span className="spinner" /> : 'Calculate Optimal Distribution'}
            </button>
            {hasResults && (
              <button type="button" className="btn btn-ghost" onClick={handleReset}>
                Reset
              </button>
            )}
          </div>
        </section>

        {hasResults && (
          <>
            <section className="summary">
              <div className="card card-count">
                <span className="card-label">Employees</span>
                <span className="card-value">{results.length}</span>
              </div>
              <div className="card card-payroll">
                <span className="card-label">Total Payroll</span>
                <span className="card-value">{fmt(payroll)}</span>
              </div>
              <div className="card card-tax">
                <span className="card-label">Total Tax Outgo</span>
                <span className="card-value">{fmt(totalTax)}</span>
              </div>
              <div className="card card-take">
                <span className="card-label">Total Take Home</span>
                <span className="card-value">{fmt(totalTakeHome)}</span>
              </div>
              <div className="card card-rate">
                <span className="card-label">Effective Tax Rate</span>
                <span className="card-value">{effTaxPct}%</span>
              </div>
            </section>

            <section className="results-section">
              <div className="table-wrap">
                <table className="results-table">
                  <thead>
                    <tr>
                      <th>#</th>
                      <th>Salary</th>
                      <th>Tax</th>
                      <th>Take Home</th>
                      <th></th>
                      <th></th>
                    </tr>
                  </thead>
                  <tbody>
                    {results.map((emp) => (
                      <EmployeeRow key={emp.index} emp={emp} />
                    ))}
                  </tbody>
                </table>
              </div>
            </section>
          </>
        )}
      </main>

      <footer className="footer">
        <span>Tax slabs: 0–2.5L (0%) · 2.5–5L (10%) · 5–10L (20%) · 10L+ (25%) · Surcharge 5% above ₹50k tax</span>
      </footer>
    </div>
  );
}

export default App;
